// src/Login.js
import React, { useState } from 'react';
import axios from 'axios';

export default function Login({ onLogin }) {
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [mensagem, setMensagem] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/login', { usuario, senha });
      onLogin(res.data);
    } catch {
      setMensagem('Usuário ou senha inválidos!');
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center px-4">
      <div className="max-w-4xl w-full grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* ---- LADO ESQUERDO (apenas desktop) ---- */}
        <div
          className="hidden md:flex items-center justify-center bg-cover bg-center rounded-l-2xl"
          style={{
            backgroundImage:
              "url('https://www.instagram.com/static/images/homepage/home-phones.png/43cc71bb1b43.png')",
          }}
        />

        {/* ---- FORMULÁRIO ---- */}
        <div className="flex flex-col items-center">
          <div className="w-full max-w-xs">
            {/* Logo */}
            <img
              src="/logo.png"
              alt="Instagram"
              className="mx-auto h-12 mb-6"
            />

            {/* Caixa branca */}
            <form
              onSubmit={handleSubmit}
              className="bg-white border border-gray-300 px-8 py-10 rounded-2xl space-y-4"
            >
              <input
                type="text"
                placeholder="Telefone, nome de usuário ou email"
                className="w-full bg-gray-50 border border-gray-300 rounded px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
                value={usuario}
                onChange={e => setUsuario(e.target.value)}
                required
              />

              <input
                type="password"
                placeholder="Senha"
                className="w-full bg-gray-50 border border-gray-300 rounded px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
                value={senha}
                onChange={e => setSenha(e.target.value)}
                required
              />

              <button
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-2 rounded disabled:opacity-50 disabled:cursor-not-allowed"
                disabled={!usuario || !senha}
              >
                Entrar
              </button>

              {mensagem && (
                <p className="text-center text-red-600 text-sm">{mensagem}</p>
              )}

              <div className="flex items-center my-2">
                <hr className="flex-grow border-t border-gray-300" />
                <span className="px-2 text-gray-500 text-sm">OU</span>
                <hr className="flex-grow border-t border-gray-300" />
              </div>

              <button
                type="button"
                className="flex items-center justify-center w-full text-blue-600 text-sm font-semibold"
              >
                {/* ícone do Facebook */}
                <svg
                  className="w-4 h-4 mr-2 fill-current"
                  viewBox="0 0 24 24"
                >
                  <path d="M22.675 0H1.325C.593 0 0 .593 0 1.326v21.348C0 23.406.593 24 1.325 24h11.495v-9.294H9.691V11.31h3.129V8.413c0-3.1 1.893-4.788 4.659-4.788 1.325 0 2.463.099 2.795.143v3.24l-1.918.001c-1.505 0-1.797.716-1.797 1.766v2.317h3.587l-.467 3.396h-3.12V24h6.116C23.406 24 24 23.406 24 22.674V1.326C24 .593 23.406 0 22.675 0z" />
                </svg>
                Entrar com Facebook
              </button>

              <a
                href="#"
                className="block text-center text-xs text-blue-600 hover:underline mt-4"
              >
                Esqueceu a senha?
              </a>
            </form>

            {/* Caixa de cadastro */}
            <div className="bg-white border border-gray-300 px-8 py-4 rounded-2xl mt-4 text-center text-sm">
              Não tem uma conta?{' '}
              <a href="#" className="text-blue-600 font-semibold hover:underline">
                Cadastre-se
              </a>
            </div>

            {/* Obtenha o app */}
            <div className="mt-6 text-center">
              <p className="text-sm mb-4">Obtenha o app.</p>
              <div className="flex justify-center space-x-2">
                <img
                  src="https://www.instagram.com/static/images/appstore-install-badges/badge_ios_english-en.svg/97ed5cb74d1b.png"
                  alt="App Store"
                  className="h-8"
                />
                <img
                  src="https://www.instagram.com/static/images/appstore-install-badges/badge_android_english-en.png/8f7deba1bd76.png"
                  alt="Google Play"
                  className="h-8"
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
